import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { toast } from 'react-toastify';

// ── helpers ────────────────────────────────────────────────────
const fmt = v => (v === null || v === undefined ? '—' : v);

// ── Excel export (SheetJS via CDN) ─────────────────────────────
async function loadXLSX() {
  if (window.XLSX) return window.XLSX;
  await new Promise((res, rej) => {
    const s = document.createElement('script');
    s.src = 'https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js';
    s.onload = res; s.onerror = rej;
    document.head.appendChild(s);
  });
  return window.XLSX;
}

async function exportExcel(sheets, filename) {
  const XLSX = await loadXLSX();
  const wb = XLSX.utils.book_new();
  sheets.forEach(({ name, data }) => {
    const ws = XLSX.utils.aoa_to_sheet(data);
    // Auto column widths
    const colW = data[0]?.map((_, ci) => ({
      wch: Math.max(...data.map(r => String(r[ci] ?? '').length), 10)
    }));
    ws['!cols'] = colW;
    XLSX.utils.book_append_sheet(wb, ws, name.slice(0, 31));
  });
  XLSX.writeFile(wb, filename);
}

// ── PDF export (jsPDF + autoTable) ─────────────────────────────
async function loadJsPDF() {
  if (window.jspdf) return window.jspdf.jsPDF;
  await new Promise((res, rej) => {
    const s = document.createElement('script');
    s.src = 'https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.1/jspdf.umd.min.js';
    s.onload = res; s.onerror = rej; document.head.appendChild(s);
  });
  await new Promise((res, rej) => {
    const s = document.createElement('script');
    s.src = 'https://cdnjs.cloudflare.com/ajax/libs/jspdf-autotable/3.5.31/jspdf.plugin.autotable.min.js';
    s.onload = res; s.onerror = rej; document.head.appendChild(s);
  });
  return window.jspdf.jsPDF;
}

async function exportPDF(title, subtitle, head, body, filename) {
  const JsPDF = await loadJsPDF();
  const doc = new JsPDF({ orientation: 'landscape' });
  doc.setFontSize(16); doc.setFont('helvetica','bold');
  doc.text('VEMU Institute of Technology', doc.internal.pageSize.width / 2, 15, { align: 'center' });
  doc.setFontSize(12); doc.setFont('helvetica','normal');
  doc.text(title, doc.internal.pageSize.width / 2, 23, { align: 'center' });
  doc.setFontSize(10);
  doc.text(subtitle, doc.internal.pageSize.width / 2, 30, { align: 'center' });
  doc.text(`Generated: ${new Date().toLocaleDateString('en-IN')}`, doc.internal.pageSize.width / 2, 36, { align: 'center' });
  doc.autoTable({
    startY: 42,
    head: [head],
    body,
    styles: { fontSize: 8, cellPadding: 2 },
    headStyles: { fillColor: [26, 86, 219], textColor: 255, fontStyle: 'bold' },
    alternateRowStyles: { fillColor: [241, 245, 249] },
    margin: { left: 10, right: 10 },
  });
  doc.save(filename);
}

// ── Card component ─────────────────────────────────────────────
function ReportCard({ icon, title, desc, onExcelDepts, onPdfDepts, onExcelSubjects, onPdfSubjects, onExcelUsers, onPdfUsers, onExcelMarks, onPdfMarks, loading }) {
  return (
    <div className="card" style={{ marginBottom: 20 }}>
      <div className="card-header">
        <span className="card-title">{icon} {title}</span>
      </div>
      <div className="card-body">
        <p style={{ color: 'var(--text-muted)', fontSize: 13, marginBottom: 16 }}>{desc}</p>
        <div style={{ display: 'flex', gap: 10, flexWrap: 'wrap' }}>
          {onExcelDepts   && <button className="btn btn-success btn-sm" onClick={onExcelDepts}   disabled={loading}>📊 Departments Excel</button>}
          {onPdfDepts     && <button className="btn btn-danger  btn-sm" onClick={onPdfDepts}     disabled={loading}>📄 Departments PDF</button>}
          {onExcelSubjects&& <button className="btn btn-success btn-sm" onClick={onExcelSubjects}disabled={loading}>📊 Subjects Excel</button>}
          {onPdfSubjects  && <button className="btn btn-danger  btn-sm" onClick={onPdfSubjects}  disabled={loading}>📄 Subjects PDF</button>}
          {onExcelUsers   && <button className="btn btn-success btn-sm" onClick={onExcelUsers}   disabled={loading}>📊 Users Excel</button>}
          {onPdfUsers     && <button className="btn btn-danger  btn-sm" onClick={onPdfUsers}     disabled={loading}>📄 Users PDF</button>}
          {onExcelMarks   && <button className="btn btn-success btn-sm" onClick={onExcelMarks}   disabled={loading}>📊 Marks Excel</button>}
          {onPdfMarks     && <button className="btn btn-danger  btn-sm" onClick={onPdfMarks}     disabled={loading}>📄 Marks PDF</button>}
        </div>
      </div>
    </div>
  );
}

export default function AdminReports() {
  const [loading, setLoading] = useState(false);
  const [depts,   setDepts]   = useState([]);
  const [selDept, setSelDept] = useState('');
  const [selSem,  setSelSem]  = useState('');
  const SEMESTERS = [1,2,3,4,5,6,7,8];

  useEffect(() => {
    axios.get('/api/admin/departments').then(r => setDepts(r.data.departments?.filter(d=>d.isActive)||[]));
  }, []);

  const wrap = async (fn) => { setLoading(true); try { await fn(); } catch(e) { toast.error('Export failed: ' + e.message); } finally { setLoading(false); } };

  // ── Institution-wide reports ──────────────────────────────────
  const excelAllUsers = () => wrap(async () => {
    const r = await axios.get('/api/admin/users');
    const users = r.data.users;
    const data = [
      ['VEMU Institute of Technology — All Users Report'],
      [`Generated: ${new Date().toLocaleDateString('en-IN')}`],
      [],
      ['#','Name','Roll Number','Role','Department','Semester','Section','Status'],
      ...users.map((u,i) => [i+1, u.name, u.rollNumber, u.role, u.department?.name||'—', u.semester||'—', u.section||'—', u.isActive?'Active':'Inactive'])
    ];
    await exportExcel([{ name:'All Users', data }], 'VEMU_All_Users.xlsx');
    toast.success('Excel downloaded!');
  });

  const pdfAllUsers = () => wrap(async () => {
    const r = await axios.get('/api/admin/users');
    await exportPDF('Institution-Wide Users Report','All Roles',
      ['#','Name','Roll No','Role','Department','Sem','Section'],
      r.data.users.map((u,i)=>[i+1,u.name,u.rollNumber,u.role,u.department?.name||'—',u.semester||'—',u.section||'—']),
      'VEMU_All_Users.pdf');
    toast.success('PDF downloaded!');
  });

  const excelAllDepts = () => wrap(async () => {
    const r = await axios.get('/api/admin/departments');
    const data = [
      ['VEMU Institute of Technology — Departments Report'],
      [`Generated: ${new Date().toLocaleDateString('en-IN')}`],
      [],
      ['#','Department Name','Code','Description','Status'],
      ...r.data.departments.map((d,i)=>[i+1,d.name,d.code,d.description||'—',d.isActive?'Active':'Inactive'])
    ];
    await exportExcel([{ name:'Departments', data }], 'VEMU_Departments.xlsx');
    toast.success('Excel downloaded!');
  });

  const pdfAllDepts = () => wrap(async () => {
    const r = await axios.get('/api/admin/departments');
    await exportPDF('Departments Report','Institution Wide',
      ['#','Department Name','Code','Description','Status'],
      r.data.departments.map((d,i)=>[i+1,d.name,d.code,d.description||'—',d.isActive?'Active':'Inactive']),
      'VEMU_Departments.pdf');
    toast.success('PDF downloaded!');
  });

  const excelAllSubjects = () => wrap(async () => {
    const r = await axios.get('/api/admin/subjects');
    const data = [
      ['VEMU Institute of Technology — All Subjects Report'],
      [`Generated: ${new Date().toLocaleDateString('en-IN')}`],
      [],
      ['#','Subject Name','Code','Department','Semester','Credits','Max Marks'],
      ...r.data.subjects.map((s,i)=>[i+1,s.name,s.code,s.department?.name||'—',`Sem ${s.semester}`,s.credits,s.maxMidMarks])
    ];
    await exportExcel([{ name:'All Subjects', data }], 'VEMU_All_Subjects.xlsx');
    toast.success('Excel downloaded!');
  });

  const pdfAllSubjects = () => wrap(async () => {
    const r = await axios.get('/api/admin/subjects');
    await exportPDF('All Subjects Report','Institution Wide',
      ['#','Subject','Code','Department','Semester','Credits'],
      r.data.subjects.map((s,i)=>[i+1,s.name,s.code,s.department?.name||'—',`Sem ${s.semester}`,s.credits]),
      'VEMU_All_Subjects.pdf');
    toast.success('PDF downloaded!');
  });

  const excelAllMarks = () => wrap(async () => {
    const r = await axios.get('/api/admin/marks');
    const data = [
      ['VEMU Institute of Technology — All Marks Entries Report'],
      [`Generated: ${new Date().toLocaleDateString('en-IN')}`],
      [],
      ['#','Student Name','Roll No','Department','Semester','Section','Subject','Code','Exam','Assignment','SHA','Q1','Q2','Q3','Q4','Q5','Q6','Best Q1/Q2','Best Q3/Q4','Best Q5/Q6','Ques Half','Total/30','Faculty','Status'],
      ...r.data.marks.map((m,i)=>[
        i+1, m.student?.name||'—', m.student?.rollNumber||'—', m.student?.department||'—',
        m.semester, m.student?.section||'—', m.subject?.name||'—', m.subject?.code||'—',
        m.midExam, m.assignmentMarks, m.shaMarks, m.q1, m.q2, m.q3, m.q4, m.q5, m.q6,
        m.bestQ1Q2, m.bestQ3Q4, m.bestQ5Q6, m.questionHalf, m.totalMarks, m.faculty?.name||'—', m.status
      ])
    ];
    await exportExcel([{ name:'All Marks', data }], 'VEMU_All_Marks.xlsx');
    toast.success('Excel downloaded!');
  });

  const pdfAllMarks = () => wrap(async () => {
    const r = await axios.get('/api/admin/marks');
    await exportPDF('All Marks Entries Report','Institution Wide',
      ['#','Student','Roll No','Sem','Subject','Exam','Total/30','Faculty','Status'],
      r.data.marks.map((m,i)=>[i+1,m.student?.name||'—',m.student?.rollNumber||'—',m.semester,m.subject?.name||'—',m.midExam,m.totalMarks,m.faculty?.name||'—',m.status]),
      'VEMU_All_Marks.pdf');
    toast.success('PDF downloaded!');
  });

  // ── Department-wise marks report ──────────────────────────────
  const excelDeptMarks = () => wrap(async () => {
    if (!selDept) return toast.error('Select a department');
    const dname = depts.find(d=>d._id===selDept)?.name || 'Dept';
    const [usersR, subjectsR, marksR] = await Promise.all([
      axios.get('/api/admin/users', { params:{ role:'student', department:selDept } }),
      axios.get('/api/admin/subjects'),
      axios.get('/api/admin/marks'),
    ]);
    const deptSubjects = subjectsR.data.subjects.filter(s=>s.department?._id===selDept || s.department===selDept);
    const deptMarks    = marksR.data.marks.filter(m=>m.department===selDept || m.student?.department===selDept);

    const sheets = [];

    // Sheet 1: Students list
    const studData = [
      [`${dname} — Students List`],[`Generated: ${new Date().toLocaleDateString('en-IN')}`],[],
      ['#','Name','Roll No','Semester','Section'],
      ...usersR.data.users.filter(u=>u.isActive).map((u,i)=>[i+1,u.name,u.rollNumber,`Sem ${u.semester}`,u.section||'—'])
    ];
    sheets.push({ name:`${dname.slice(0,15)} Students`, data:studData });

    // Sheet 2: Subjects
    const subjData = [
      [`${dname} — Subjects`],[`Generated: ${new Date().toLocaleDateString('en-IN')}`],[],
      ['#','Subject','Code','Semester','Credits'],
      ...deptSubjects.map((s,i)=>[i+1,s.name,s.code,`Sem ${s.semester}`,s.credits])
    ];
    sheets.push({ name:`${dname.slice(0,15)} Subjects`, data:subjData });

    // Sheet 3: Marks
    const marksData = [
      [`${dname} — Marks Report`],[`Generated: ${new Date().toLocaleDateString('en-IN')}`],[],
      ['#','Student','Roll No','Sem','Section','Subject','Exam','Assignment/5','SHA/10','Q-Half/15','Total/30','Status'],
      ...deptMarks.map((m,i)=>[i+1,m.student?.name||'—',m.student?.rollNumber||'—',m.semester,m.student?.section||'—',m.subject?.name||'—',m.midExam,m.assignmentMarks,m.shaMarks,m.questionHalf,m.totalMarks,m.status])
    ];
    sheets.push({ name:`${dname.slice(0,15)} Marks`, data:marksData });

    await exportExcel(sheets, `VEMU_${dname}_Report.xlsx`);
    toast.success('Department report Excel downloaded!');
  });

  const pdfDeptMarks = () => wrap(async () => {
    if (!selDept) return toast.error('Select a department');
    const dname = depts.find(d=>d._id===selDept)?.name || 'Dept';
    const marksR = await axios.get('/api/admin/marks');
    const deptMarks = marksR.data.marks.filter(m=>m.department===selDept || m.student?.department===selDept);
    await exportPDF(`${dname} — Marks Report`, 'Department Level',
      ['#','Student','Roll No','Sem','Section','Subject','Exam','Assignment','SHA','Total/30','Status'],
      deptMarks.map((m,i)=>[i+1,m.student?.name||'—',m.student?.rollNumber||'—',m.semester,m.student?.section||'—',m.subject?.name||'—',m.midExam,m.assignmentMarks,m.shaMarks,m.totalMarks,m.status]),
      `VEMU_${dname}_Marks.pdf`);
    toast.success('PDF downloaded!');
  });

  // ── Class/Semester-wise report ────────────────────────────────
  const excelSemMarks = () => wrap(async () => {
    if (!selDept || !selSem) return toast.error('Select department and semester');
    const dname = depts.find(d=>d._id===selDept)?.name || 'Dept';
    const marksR = await axios.get('/api/admin/marks');
    const semMarks = marksR.data.marks.filter(m => m.semester === Number(selSem));
    const mid1 = semMarks.filter(m=>m.midExam==='Mid-1');
    const mid2 = semMarks.filter(m=>m.midExam==='Mid-2');
    const sheets = [
      { name:`Sem ${selSem} Mid-1`, data:[
        [`Semester ${selSem} — Mid-1 Marks`],[`Generated: ${new Date().toLocaleDateString('en-IN')}`],[],
        ['#','Student','Roll No','Section','Subject','Asgn/5','SHA/10','Q-Half/15','Total/30','Status'],
        ...mid1.map((m,i)=>[i+1,m.student?.name||'—',m.student?.rollNumber||'—',m.student?.section||'—',m.subject?.name||'—',m.assignmentMarks,m.shaMarks,m.questionHalf,m.totalMarks,m.status])
      ]},
      { name:`Sem ${selSem} Mid-2`, data:[
        [`Semester ${selSem} — Mid-2 Marks`],[`Generated: ${new Date().toLocaleDateString('en-IN')}`],[],
        ['#','Student','Roll No','Section','Subject','Asgn/5','SHA/10','Q-Half/15','Total/30','Status'],
        ...mid2.map((m,i)=>[i+1,m.student?.name||'—',m.student?.rollNumber||'—',m.student?.section||'—',m.subject?.name||'—',m.assignmentMarks,m.shaMarks,m.questionHalf,m.totalMarks,m.status])
      ]}
    ];
    await exportExcel(sheets, `VEMU_Sem${selSem}_Marks.xlsx`);
    toast.success('Class-wise report downloaded!');
  });

  const pdfSemMarks = () => wrap(async () => {
    if (!selDept || !selSem) return toast.error('Select department and semester');
    const marksR = await axios.get('/api/admin/marks');
    const semMarks = marksR.data.marks.filter(m=>m.semester===Number(selSem));
    await exportPDF(`Semester ${selSem} Marks Report`, `Class-wise Report`, 
      ['#','Student','Roll No','Section','Subject','Exam','Total/30','Status'],
      semMarks.map((m,i)=>[i+1,m.student?.name||'—',m.student?.rollNumber||'—',m.student?.section||'—',m.subject?.name||'—',m.midExam,m.totalMarks,m.status]),
      `VEMU_Sem${selSem}_Marks.pdf`);
    toast.success('PDF downloaded!');
  });

  return (
    <div>
      <div className="page-header">
        <div><div className="page-title">📋 Reports</div><div className="page-subtitle">Generate and download institution-wide reports</div></div>
      </div>

      {/* ── 1. Institution Level ── */}
      <div className="card" style={{ marginBottom: 20 }}>
        <div className="card-header"><span className="card-title">🏛️ Institution-Wide Reports</span></div>
        <div className="card-body">
          <p style={{ color:'var(--text-muted)', fontSize:13, marginBottom:16 }}>Download complete data across all departments</p>
          <div style={{ display:'flex', gap:10, flexWrap:'wrap' }}>
            <button className="btn btn-success btn-sm" onClick={excelAllUsers}    disabled={loading}>📊 All Users Excel</button>
            <button className="btn btn-danger  btn-sm" onClick={pdfAllUsers}      disabled={loading}>📄 All Users PDF</button>
            <button className="btn btn-success btn-sm" onClick={excelAllDepts}    disabled={loading}>📊 Departments Excel</button>
            <button className="btn btn-danger  btn-sm" onClick={pdfAllDepts}      disabled={loading}>📄 Departments PDF</button>
            <button className="btn btn-success btn-sm" onClick={excelAllSubjects} disabled={loading}>📊 Subjects Excel</button>
            <button className="btn btn-danger  btn-sm" onClick={pdfAllSubjects}   disabled={loading}>📄 Subjects PDF</button>
            <button className="btn btn-success btn-sm" onClick={excelAllMarks}    disabled={loading}>📊 All Marks Excel</button>
            <button className="btn btn-danger  btn-sm" onClick={pdfAllMarks}      disabled={loading}>📄 All Marks PDF</button>
          </div>
        </div>
      </div>

      {/* ── 2. Department Level ── */}
      <div className="card" style={{ marginBottom: 20 }}>
        <div className="card-header"><span className="card-title">🏢 Department-Level Report</span></div>
        <div className="card-body">
          <p style={{ color:'var(--text-muted)', fontSize:13, marginBottom:12 }}>Select a department to generate students, subjects and marks report</p>
          <div style={{ display:'flex', gap:10, alignItems:'center', flexWrap:'wrap', marginBottom:16 }}>
            <select className="form-select" style={{ width:240 }} value={selDept} onChange={e=>setSelDept(e.target.value)}>
              <option value="">Select Department</option>
              {depts.map(d=><option key={d._id} value={d._id}>{d.name} ({d.code})</option>)}
            </select>
          </div>
          <div style={{ display:'flex', gap:10, flexWrap:'wrap' }}>
            <button className="btn btn-success btn-sm" onClick={excelDeptMarks} disabled={loading||!selDept}>📊 Department Excel (3 sheets)</button>
            <button className="btn btn-danger  btn-sm" onClick={pdfDeptMarks}   disabled={loading||!selDept}>📄 Department Marks PDF</button>
          </div>
        </div>
      </div>

      {/* ── 3. Class/Semester Level ── */}
      <div className="card" style={{ marginBottom: 20 }}>
        <div className="card-header"><span className="card-title">📚 Class-wise / Semester Report</span></div>
        <div className="card-body">
          <p style={{ color:'var(--text-muted)', fontSize:13, marginBottom:12 }}>Select department + semester to get Mid-1 & Mid-2 class marks</p>
          <div style={{ display:'flex', gap:10, alignItems:'center', flexWrap:'wrap', marginBottom:16 }}>
            <select className="form-select" style={{ width:220 }} value={selDept} onChange={e=>setSelDept(e.target.value)}>
              <option value="">Select Department</option>
              {depts.map(d=><option key={d._id} value={d._id}>{d.name} ({d.code})</option>)}
            </select>
            <select className="form-select" style={{ width:160 }} value={selSem} onChange={e=>setSelSem(e.target.value)}>
              <option value="">Select Semester</option>
              {SEMESTERS.map(s=><option key={s} value={s}>Semester {s}</option>)}
            </select>
          </div>
          <div style={{ display:'flex', gap:10, flexWrap:'wrap' }}>
            <button className="btn btn-success btn-sm" onClick={excelSemMarks} disabled={loading||!selDept||!selSem}>📊 Class Marks Excel (Mid-1 + Mid-2)</button>
            <button className="btn btn-danger  btn-sm" onClick={pdfSemMarks}   disabled={loading||!selDept||!selSem}>📄 Class Marks PDF</button>
          </div>
        </div>
      </div>

      {loading && (
        <div style={{ textAlign:'center', padding:20, color:'var(--text-muted)', fontSize:13 }}>
          ⏳ Generating report, please wait...
        </div>
      )}
    </div>
  );
}
